from datetime import datetimefrom pathlib import Pathimport pandas as pdimport numpy as npfrom sklearn.metrics import confusion_matrixfrom experiments.orion.elib import (    create_orion_training_data,    split_training_data,    zscore_feature_columns,    print_training_data_stats,)import numpy as npimport pandas as pdfrom sklearn.metrics import confusion_matrixfrom lib.common.common import evaluate_and_print, calculate_min_win_ratedef evaluate_and_print_trade_zhongjie(    name: str,    y_test: pd.Series,    y_pred: np.ndarray,    *,    take_profit: float = 0.04,    stop_loss: float = 0.02,    cost: float = 0.004,) -> None:    print(f"\n--- {name} ---")    cm = confusion_matrix(y_test, y_pred)    tp_count = int(cm[1, 1])    fp_count = int(cm[0, 1])    fn_count = int(cm[1, 0])    tn_count = int(cm[0, 0])    pos_denom = tp_count + fn_count    pred_pos_denom = tp_count + fp_count    recall_pct = 100 * tp_count / pos_denom if pos_denom else 0.0    precision_pct = 100 * tp_count / pred_pos_denom if pred_pos_denom else 0.0    loss_pct = 100 * fp_count / pred_pos_denom if pred_pos_denom else 0.0    accuracy_pct = 100 * (tp_count + tn_count) / len(y_test) if len(y_test) else 0.0    print(f"Profitable Trades Taken (Recall): {tp_count:,}/{pos_denom:,} ({recall_pct:,.2f}%)")    print(f"Win Rate (Precision): {tp_count:,}/{pred_pos_denom:,} ({precision_pct:,.2f}%)")    print(f"Loss Rate: {fp_count:,}/{pred_pos_denom:,} ({loss_pct:,.2f}%)")    print(f"True Positives: {tp_count:,}/{pos_denom:,} ({recall_pct:,.2f}%)")    print(f"True Negatives: {tn_count:,} / {len(y_test):,} ({100 * tn_count / len(y_test):.2f}%)")    print(f"Accuracy: {tp_count + tn_count:,} / {len(y_test):,} ({accuracy_pct:.2f}%)")    win_per = take_profit - cost    loss_per = stop_loss + cost    realized_profit = tp_count * win_per - fp_count * loss_per    max_possible_profit = pos_denom * win_per    min_win_rate = 100 * calculate_min_win_rate(take_profit, stop_loss, cost)    print(f"Trades Taken: {pred_pos_denom:,}")    print(f"Realized Profit: {100 * realized_profit:,.2f}%")    print(f"Max Possible Profit: {100 * max_possible_profit:,.2f}%")    print(f"Break-even Win Rate: {min_win_rate:,.2f}%")    if max_possible_profit != 0:        capture_pct = 100 * realized_profit / max_possible_profit        print(f"Profit Capture vs Max Possible: {capture_pct:,.2f}%")    if pred_pos_denom:        gap = precision_pct - min_win_rate        print(f"Win Rate - Break-even Gap: {gap:,.2f} pts")_CACHE_DIR = Path("etc/data/zhongjie")def my_cache_path(symbol: str, start: datetime, end: datetime) -> Path:    start_s = start.strftime("%Y%m%d")    end_s = end.strftime("%Y%m%d")    return _CACHE_DIR / f"{symbol}_{start_s}_{end_s}_1min.csv"def pull_and_clean(symbol: str, start: datetime, end: datetime) -> pd.DataFrame:    from alpaca.data.timeframe import TimeFrame    from lib.stock.data_cleaner import StockDataCleaner    from lib.stock.data_fetcher import StockDataFetcher    path = my_cache_path(symbol, start, end)    if path.exists():        print(f"Loading cached data: {path.name}")        data = pd.read_csv(path, index_col=[0, 1], parse_dates=[1])        if data.index.levels[1].tz is None:            data.index = data.index.set_levels(                data.index.levels[1].tz_localize("UTC"), level=1            )        return data    fetcher = StockDataFetcher()    data = fetcher.get_historical_bars(        symbol=symbol,        start_date=start,        end_date=end,        timeframe=TimeFrame.Minute,    )    cleaner = StockDataCleaner()    data = cleaner.remove_closed_market_rows(data)    data = cleaner.forward_propagate(        data,        TimeFrame.Minute,        only_when_market_open=True,        mark_imputed_rows=False,    )    _CACHE_DIR.mkdir(parents=True, exist_ok=True)    data.to_csv(path)    print(f"Cached cleaned data to {path.name}")    return datadef load_zhongjie_training_frames(    *,    symbol: str,    reference_symbols: tuple[str, ...],    start_date: datetime,    end_date: datetime,    take_profit: float,    stop_loss: float,    validation_fraction: float,    test_fraction: float,    target_max_bars_after_entry: int | None = None,    print_split: bool = True,    only_rows_hitting_tp_or_sl: bool = False,) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:    raw_df = pull_and_clean(symbol, start_date, end_date)    reference_df = pd.concat(        [pull_and_clean(s, start_date, end_date) for s in reference_symbols],        axis=0,    ).sort_index()    training_df = create_orion_training_data(        raw_df,        take_profit=take_profit,        stop_loss=stop_loss,        reference_bars=reference_df,        max_bars_after_entry=target_max_bars_after_entry,        only_rows_hitting_tp_or_sl=only_rows_hitting_tp_or_sl,    )    train_df, val_df, test_df = split_training_data(        training_df,        validation_fraction=validation_fraction,        test_fraction=test_fraction,    )    train_df, val_df, test_df = zscore_feature_columns(train_df, val_df, test_df)    if print_split:        print_training_data_stats(train_df, val_df, test_df)    return train_df, val_df, test_df